css:
.rmax-zatca { font-family: 'Segoe UI', 'Helvetica Neue', Arial, 'Tahoma', sans-serif; font-size: 9pt; color: #000; }
.rmax-zatca table { width: 100%; border-collapse: collapse; }
.rmax-zatca td, .rmax-zatca th { padding: 3px 5px; vertical-align: top; }
.rmax-zatca .rmax-bordered td, .rmax-zatca .rmax-bordered th { border: 1px solid #333; }
.rmax-title-bar { background: #f3f3f3; border: 1px solid #333; padding: 6px; font-size: 14pt; text-align: center; font-weight: bold; margin-top: 6px; }
.rmax-title-bar .rmax-page { float: right; font-size: 9pt; font-weight: normal; }
.rmax-section-label { background: #efefef; font-weight: bold; padding: 4px 6px; }
.rmax-rtl { direction: rtl; text-align: right; }
.rmax-center { text-align: center; }
.rmax-right { text-align: right; }
.rmax-bold { font-weight: bold; }
.rmax-col-label { width: 18%; }
.rmax-col-value { width: 32%; }
.rmax-buyer { margin-top: 6px; }
.rmax-buyer .rmax-col-label { width: 14%; }
.rmax-buyer .rmax-col-value { width: 36%; }
.rmax-items { margin-top: 6px; }
.rmax-items th { background: #f3f3f3; font-weight: bold; text-align: center; font-size: 8.5pt; }
.rmax-items td { font-size: 9pt; }
.rmax-totals-wrap { margin-top: 6px; }
.rmax-totals-wrap .rmax-qr-cell { width: 25%; vertical-align: top; text-align: center; }
.rmax-totals-wrap .rmax-totals-cell { vertical-align: top; }
.rmax-totals td { font-weight: bold; }
.rmax-totals .rmax-tot-en { width: 35%; }
.rmax-totals .rmax-tot-ar { width: 45%; }
.rmax-totals .rmax-tot-num { width: 20%; }
.rmax-totals-ar { float: right; }
.rmax-qr { width: 110px; height: 110px; }
.rmax-footer { margin-top: 10px; }
.rmax-footer td { width: 25%; }
.rmax-banks { margin-top: 8px; }
@media print { .rmax-zatca { font-size: 9pt; } }
